   310→    public sealed class TransformationOrchestrator
   311→    {
   312→        private readonly IDictionary<KpiType, ITransformationStrategy> _strategyLookup;
   313→        private readonly ILogger<TransformationOrchestrator> _logger;
   314→
   315→        public TransformationOrchestrator(
   316→            IEnumerable<ITransformationStrategy> strategies,
   317→            ILogger<TransformationOrchestrator> logger)
   318→        {
   319→            _logger = logger;
   320→            _strategyLookup = strategies.ToDictionary(s => s.TargetKpi, s => s);
   321→        }
