   323→        /// <summary>
   324→        /// Core entry point used by Lambda Function Handler.
   325→        /// </summary>
   326→        /// <param name="events">Homogeneous set of raw events belonging to a single tenant + day.</param>
   327→        /// <param name="kpiTypes">Subset of KPIs to calculate.  Null means “all registered”.</param>
   328→        /// <param name="cancellationToken">Cancellation token propagated from runtime.</param>
   329→        /// <returns>Flattened collection of <see cref="KpiRecord"/> objects.</returns>
   330→        /// <exception cref="InvalidOperationException">
   331→        /// Thrown when a requested KPI is missing a strategy implementation.
   332→        /// </exception>
   333→        public async Task<IReadOnlyCollection<KpiRecord>> ExecuteAsync(
   334→            IReadOnlyCollection<RawEvent> events,
   335→            IEnumerable<KpiType>? kpiTypes = null,
   336→            CancellationToken cancellationToken = default)
