   339→            {
   340→                _logger.LogWarning("TransformationOrchestrator invoked with empty event set.");
   341→                return Array.Empty<KpiRecord>();
   342→            }
   343→
   344→            var requestedKpis = kpiTypes?.ToImmutableHashSet() ?? _strategyLookup.Keys.ToImmutableHashSet();
   345→
   346→            // Validate strategy coverage.
   347→            var missing = requestedKpis.Where(k => !_strategyLookup.ContainsKey(k)).ToArray();
   348→            if (missing.Length > 0)
   349→            {
   350→                throw new InvalidOperationException(
   351→                    $"No strategy implementation found for KPI(s): {string.Join(", ", missing)}");
   352→            }
   353→
   354→            // Parallelize across strategies to fully leverage Lambda’s CPU allocation.
   355→            var tasks = requestedKpis
   356→                .Select(kpi => ExecuteStrategyAsync(_strategyLookup[kpi], events, cancellationToken))
   357→                .ToArray();
   358→
   359→            var results = await Task.WhenAll(tasks);
   360→            return results.SelectMany(r => r).ToImmutableArray();
   361→        }
   362→
   363→        private async Task<IReadOnlyCollection<KpiRecord>> ExecuteStrategyAsync(
   364→            ITransformationStrategy strategy,
   365→            IReadOnlyCollection<RawEvent> events,
   366→            CancellationToken cancellationToken)
   367→        {
   368→            try
   369→            {
   370→                var sw = Stopwatch.StartNew();
   371→                var output = await strategy.TransformAsync(events, cancellationToken);
