    37→    /// <summary>
    38→    /// Entry-point Lambda handler for processing Kinesis ingestion shards.
    39→    /// </summary>
    40→    public sealed class KinesisStreamProcessor
    41→    {
    42→        private readonly IServiceProvider _root;
    43→        private readonly ILogger _log;
    44→
    45→        public KinesisStreamProcessor()
    46→        {
    47→            _root = ConfigureServices();
    48→            _log = _root.GetRequiredService<ILogger>().ForContext<KinesisStreamProcessor>();
    49→
    50→            _log.Information("KinesisStreamProcessor cold-start completed — DI container initialised.");
    51→        }
