    53→        // ---------------------------------------------------------------------
    54→        //  Lambda Handler
    55→        // ---------------------------------------------------------------------
    56→        /// <summary>
    57→        /// AWS Lambda runtime invokes this async handler for each micro-batch that
    58→        /// Kinesis pushes.  Batch size &amp; window are configured via Kinesis event
    59→        /// source mapping (IaC – see cdk/KinesisIngestionStack.cs).
    60→        /// </summary>
    61→        public async Task HandleAsync(KinesisEvent kinesisEvent, ILambdaContext context)
    62→        {
    63→            _log.ForContext("Records", kinesisEvent.Records.Count)
    64→                .Information("Received Kinesis micro-batch.");
    65→
    66→            var validator  = _root.GetRequiredService<IEventEnvelopeValidator>();
    67→            var selector   = _root.GetRequiredService<ITransformationStrategySelector>();
    68→            var dispatcher = _root.GetRequiredService<ITransformedEventDispatcher>();
    69→
    70→            // Process in parallel – concurrency governed by reserved Lambda memory.
    71→            await Parallel.ForEachAsync(
    72→                kinesisEvent.Records,
    73→                new ParallelOptions { MaxDegreeOfParallelism = Environment.ProcessorCount },
    74→                async (record, ct) =>
    75→                {
    76→                    try
    77→                    {
    78→                        var envelope = DeserializeEnvelope(record);
    79→                        validator.Validate(envelope);             // throws if invalid
    80→
    81→                        var strategy = selector.Resolve(envelope.EventType);
    82→                        var result   = await strategy.TransformAsync(envelope, ct);
    83→
    84→                        await dispatcher.DispatchAsync(result, ct);
    85→                    }
    86→                    catch (ValidationException vex)
    87→                    {
    88→                        _log.Warning(vex, "Validation failure.  Record sent to DLQ.");
    89→                        await dispatcher.DeadLetterAsync(record, vex, ct);
    90→                    }
    91→                    catch (Exception ex)
    92→                    {
    93→                        _log.Error(ex, "Unhandled exception.  Record sent to DLQ.");
    94→                        await dispatcher.DeadLetterAsync(record, ex, ct);
    95→                    }
    96→                });
    97→        }
