   102→        private static EventEnvelope DeserializeEnvelope(KinesisEvent.KinesisEventRecord record)
   103→        {
   104→            // Kinesis enforces a Base64 encoded string.  We decode quickly using
   105→            // ArrayPool to avoid allocations on high throughput.
   106→            var dataSpan = record.Kinesis.Data.Span;
   107→            var rented   = ArrayPool<byte>.Shared.Rent(dataSpan.Length);
   108→            try
   109→            {
   110→                dataSpan.CopyTo(rented);
   111→                var json = Encoding.UTF8.GetString(rented, 0, dataSpan.Length);
   112→
   113→                return JsonSerializer.Deserialize<EventEnvelope>(json)!;
   114→            }
   115→            finally
   116→            {
   117→                ArrayPool<byte>.Shared.Return(rented);
   118→            }
   119→        }
