   181→    public sealed class DefaultEnvelopeValidator : IEventEnvelopeValidator
   182→    {
   183→        private readonly ILogger _log;
   184→
   185→        public DefaultEnvelopeValidator(ILogger log) => _log = log;
   186→
   187→        public void Validate(EventEnvelope envelope)
   188→        {
   189→            if (string.IsNullOrWhiteSpace(envelope.EventType))
   190→            {
   191→                throw new ValidationException("EventType is required.");
   192→            }
   193→
   194→            if (envelope.TimestampUtc == default)
   195→            {
   196→                throw new ValidationException("TimestampUtc is required.");
   197→            }
   198→
   199→            if (envelope.Payload.ValueKind == JsonValueKind.Undefined ||
   200→                envelope.Payload.ValueKind == JsonValueKind.Null)
   201→            {
   202→                throw new ValidationException("Payload cannot be null or undefined.");
   203→            }
   204→
   205→            _log.Debug("Envelope validation passed for type {EventType}", envelope.EventType);
   206→        }
   207→    }
