   248→    public sealed class CalendarEventTransformationStrategy : ITransformationStrategy
   249→    {
   250→        public Task<TransformedEvent> TransformAsync(EventEnvelope envelope, CancellationToken ct)
   251→        {
   252→            // Example: Enrich meeting duration & cost statistics
   253→            var source = envelope.Payload;
   254→
   255→            var attendees  = source.GetProperty("attendees").GetArrayLength();
   256→            var durationMs = source.GetProperty("duration_ms").GetInt64();
   257→            var hourlyRate = 65; // USD – in practice looked up from DB
   258→
   259→            var meetingCost = (durationMs / 1000 / 60.0 / 60.0) * attendees * hourlyRate;
   260→
   261→            var enriched = new
   262→            {
   263→                attendees,
   264→                duration_ms  = durationMs,
   265→                meeting_cost = meetingCost,
   266→                source_id    = source.GetProperty("id").GetString()
   267→            };
   268→
   269→            return Task.FromResult(
   270→                new TransformedEvent(
   271→                    NormalisedType : "meeting_metrics",
   272→                    Payload        : JsonSerializer.SerializeToElement(enriched),
   273→                    ObservedAtUtc  : envelope.TimestampUtc,
   274→                    Tags           : new Dictionary<string, string>
   275→                    {
   276→                        ["source"] = "calendar"
   277→                    }));
   278→        }
   279→    }
