   342→    public interface ITransformedEventDispatcher
   343→    {
   344→        Task DispatchAsync(TransformedEvent evt, CancellationToken ct);
   345→        Task DeadLetterAsync(KinesisEvent.KinesisEventRecord rawRecord, Exception ex, CancellationToken ct);
