   348→    /// <summary>
   349→    /// Fire-and-forget dispatcher that pushes transformed events onto a downstream
   350→    /// Kinesis stream.  If no stream is configured (e.g. local tests), we fall
   351→    /// back to logging.
   352→    /// </summary>
   353→    public sealed class FireAndForgetDispatcher : ITransformedEventDispatcher, IDisposable
   354→    {
   355→        private readonly ILogger _log;
   356→        private readonly IAmazonKinesis _kinesis;
   357→        private readonly string _targetStreamName;
   358→        private readonly ConcurrentQueue<Amazon.Kinesis.Model.PutRecordsRequestEntry> _buffer = new();
   359→
   360→        public FireAndForgetDispatcher(ILogger log)
   361→        {
   362→            _log              = log;
   363→            _kinesis          = new AmazonKinesisClient(); // region inferred from Lambda environment
   364→            _targetStreamName = Environment.GetEnvironmentVariable("TRANSFORMED_STREAM_NAME") 
   365→                                ?? "pulseops-transformed-events";
   366→        }
   367→
   368→        public Task DispatchAsync(TransformedEvent evt, CancellationToken ct)
   369→        {
   370→            var json   = JsonSerializer.Serialize(evt);
   371→            var record = new Amazon.Kinesis.Model.PutRecordsRequestEntry
   372→            {
   373→                PartitionKey = evt.Tags.TryGetValue("source", out var source) ? source : "unknown",
   374→                Data         = new MemoryStream(Encoding.UTF8.GetBytes(json))
   375→            };
   376→
   377→            _buffer.Enqueue(record);
   378→
   379→            // Flush in background if we crossed threshold (imperfect, but keeps demo short)
   380→            if (_buffer.Count >= 500)
   381→            {
   382→                _ = FlushAsync(CancellationToken.None);
   383→            }
   384→
   385→            return Task.CompletedTask;
   386→        }
   387→
   388→        public async Task DeadLetterAsync(KinesisEvent.KinesisEventRecord rawRecord, Exception ex, CancellationToken ct)
   389→        {
   390→            // Pipe to DLQ – in demo we just log.  In production it’s an SQS DLQ.
   391→            _log.Warning(ex, "Dead-lettering record {@PartitionKey}", rawRecord.Kinesis.PartitionKey);
   392→            await Task.CompletedTask;
   393→        }
   394→
   395→        private async Task FlushAsync(CancellationToken ct)
   396→        {
   397→            if (_buffer.IsEmpty) return;
   398→
   399→            var batch = new List<Amazon.Kinesis.Model.PutRecordsRequestEntry>();
   400→            while (batch.Count < 500 && _buffer.TryDequeue(out var entry))
   401→            {
   402→                batch.Add(entry);
   403→            }
   404→
   405→            if (batch.Count == 0) return;
   406→
   407→            var request = new Amazon.Kinesis.Model.PutRecordsRequest
   408→            {
   409→                StreamName = _targetStreamName,
   410→                Records    = batch
   411→            };
   412→
   413→            var response = await _kinesis.PutRecordsAsync(request, ct);
   414→
   415→            if (response.FailedRecordCount > 0)
   416→            {
   417→                _log.Error("Failed to write {Failed}/{Total} records to stream {Stream}",
   418→                           response.FailedRecordCount, batch.Count, _targetStreamName);
   419→            }
   420→            else
   421→            {
   422→                _log.Information("Flushed {Count} transformed events to stream {Stream}",
   423→                                 batch.Count, _targetStreamName);
   424→            }
   425→        }
   426→
   427→        public void Dispose() => _ = FlushAsync(CancellationToken.None);
   428→    }
   429→}
