    26→        public TransformationDispatcher(
    27→            IEnumerable<ITransformationStrategy> strategies,
    28→            IDeadLetterSink deadLetterSink,
    29→            ILogger<TransformationDispatcher> logger)
    30→        {
    31→            _strategies     = strategies?.ToArray() ?? throw new ArgumentNullException(nameof(strategies));
    32→            if (!_strategies.Any())
    33→            {
    34→                throw new ArgumentException("At least one transformation strategy must be registered.", nameof(strategies));
    35→            }
    36→
    37→            _deadLetterSink = deadLetterSink ?? throw new ArgumentNullException(nameof(deadLetterSink));
    38→            _logger         = logger          ?? throw new ArgumentNullException(nameof(logger));
    39→        }
    40→
    41→        /// <summary>
    42→        /// Applies the matching strategy to every event in <paramref name="batch"/>.  
    43→        /// Events that fail transformation are shunted to the configured DLQ sink.
    44→        /// </summary>
    45→        public async Task<IReadOnlyCollection<KpiRecord>> TransformBatchAsync(
    46→            IReadOnlyCollection<EventEnvelope> batch,
    47→            CancellationToken                    ct = default)
    48→        {
    49→            if (batch is null) throw new ArgumentNullException(nameof(batch));
    50→
    51→            var output = new List<KpiRecord>(batch.Count);
    52→            var gate   = new object();
    53→
    54→            await Parallel.ForEachAsync(batch, ct, async (envelope, token) =>
    55→            {
    56→                try
    57→                {
    58→                    var strategy = _strategies.FirstOrDefault(s => s.CanHandle(envelope))
    59→                                   ?? throw new UnsupportedEventException(envelope);
    60→
    61→                    var kpi = await strategy.TransformAsync(envelope, token).ConfigureAwait(false);
    62→
    63→                    if (kpi is not null)
    64→                    {
    65→                        lock (gate) { output.Add(kpi); }
    66→                    }
    67→                }
    68→                catch (Exception ex)
    69→                {
    70→                    _logger.LogError(ex, "Failed to transform event {EventId}", envelope.Id);
    71→                    await _deadLetterSink.PublishAsync(envelope, ex, token).ConfigureAwait(false);
    72→                }
    73→            });
    74→
    75→            return output.AsReadOnly();
    76→        }
    77→    }
