   142→                envelope.Id,
   143→                envelope.EventType,
   144→                envelope.Timestamp,
   145→                envelope.Payload,
   146→                Error       = ex.ToString(),
   147→                PublishedAt = DateTimeOffset.UtcNow
   148→            };
