    22→    /// entering the <c>main</c> branch and that same commit being deployed
    23→    /// to a production environment.
    24→    ///
    25→    /// ┌──────────────────────────┐      ┌─────────────────────────────┐
    26→    /// │ CommitEvent (git push)   │ ───► │  DeploymentEvent (prod)     │
    27→    /// └──────────────────────────┘      └─────────────────────────────┘
    28→    ///                       ▲
    29→    ///                       └─  Lead-Time
    30→    ///
    31→    /// The implementation is stream-centric and memory-efficient; it is
    32→    /// able to process unbounded, out-of-order streams (Kinesis, Kafka, S3
    33→    /// object enumeration, etc.) by utilising asynchronous channels and a
    34→    /// bounded in-memory cache for correlation.
    35→    /// </summary>
    36→    public sealed class DeploymentLeadTimeStrategy : IKpiTransformationStrategy
    37→    {
    38→        private const int CacheCapacity = 10_000;                           // ~ configurable
    39→        private static readonly TimeSpan CommitRetention = TimeSpan.FromDays(14);
    40→
    41→        private readonly ILogger<DeploymentLeadTimeStrategy> _logger;
    42→        private readonly IMetricSink _metricSink;
