    45→        public DeploymentLeadTimeStrategy(
    46→            ILogger<DeploymentLeadTimeStrategy> logger,
    47→            IMetricSink metricSink,
    48→            IClock clock)
    49→        {
    50→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
    51→            _metricSink = metricSink ?? throw new ArgumentNullException(nameof(metricSink));
