    56→
    57→        /// <inheritdoc />
    58→        public async ValueTask TransformAsync(
    59→            IAsyncEnumerable<DataRecord> records,
    60→            CancellationToken cancellationToken = default)
    61→        {
    62→            var correlationCache = new CorrelationCache(CacheCapacity);
    63→
    64→            await foreach (var record in records.WithCancellation(cancellationToken).ConfigureAwait(false))
    65→            {
    66→                if (record is CommitEvent commit)
    67→                {
    68→                    correlationCache.SaveCommit(commit);
    69→                    _logger.LogTrace("Cached commit {CommitSha} at {Timestamp}", commit.Sha, commit.Timestamp);
    70→                }
