    87→                            "Negative lead-time detected for commit {CommitSha}: {LeadTime}. " +
    88→                            "Timestamps may be skewed.",
    89→                            deployment.CommitSha,
    90→                            leadTime);
    91→                        continue;
    92→                    }
    93→
    94→                    var metric = new KpiMetric(
    95→                        name: "deployment_lead_time_minutes",
    96→                        value: leadTime.TotalMinutes,
    97→                        timestamp: deployment.Timestamp,
    98→                        tags: new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase)
    99→                        {
   100→                            ["service"] = deployment.Service,
   101→                            ["environment"] = deployment.Environment
   102→                        });
