   118→
   119→        /// <summary>
   120→        /// Bounded, thread-safe correlation cache.
   121→        /// </summary>
   122→        private sealed class CorrelationCache
   123→        {
   124→            private readonly int _capacity;
   125→            private readonly ConcurrentDictionary<string, DateTimeOffset> _commitIndex;
   126→            private readonly Channel<CommitEvent> _evictionChannel;
   127→
   128→            public CorrelationCache(int capacity)
   129→            {
   130→                _capacity = capacity;
   131→                _commitIndex = new ConcurrentDictionary<string, DateTimeOffset>(StringComparer.Ordinal);
   132→                _evictionChannel = Channel.CreateBounded<CommitEvent>(
   133→                    new BoundedChannelOptions(capacity)
   134→                    {
   135→                        SingleReader = true,
   136→                        SingleWriter = true,
   137→                        FullMode = BoundedChannelFullMode.DropOldest
   138→                    });
