   140→                // Kick off eviction consumer.
   141→                _ = Task.Run(EvictAsync);
   142→            }
   143→
   144→            public void SaveCommit(CommitEvent commit)
   145→            {
   146→                if (_commitIndex.TryAdd(commit.Sha, commit.Timestamp))
   147→                {
   148→                    _evictionChannel.Writer.TryWrite(commit);
   149→                }
   150→            }
