   155→            public void Purge(DateTimeOffset threshold)
   156→            {
   157→                foreach (var kvp in _commitIndex)
   158→                {
   159→                    if (kvp.Value < threshold)
   160→                    {
   161→                        _commitIndex.TryRemove(kvp.Key, out _);
   162→                    }
   163→                }
   164→            }
