    42→    /// <summary>
    43→    /// Base contract for any transformation strategy that converts an input
    44→    /// <see cref="DataRecord"/> to an enriched version of itself or to an
    45→    /// aggregated KPI record.
    46→    /// </summary>
    47→    public interface ITransformationStrategy
    48→    {
    49→        /// <summary>
    50→        /// Globally unique identifier for this strategy.  Used for metrics,
    51→        /// diagnostics, and registry lookup.
    52→        /// </summary>
    53→        string Identifier { get; }
    54→
    55→        /// <summary>
    56→        /// Returns <see langword="true"/> if the strategy can handle the given
    57→        /// record (cheap heuristic only).  The pipeline short-circuits on the
    58→        /// first strategy that claims responsibility.
    59→        /// </summary>
    60→        bool CanHandle(in DataRecord record);
    61→
    62→        /// <summary>
    63→        /// Performs the actual transformation asynchronously.
    64→        /// Implementations must be side-effect-free and thread-safe.
    65→        /// </summary>
    66→        /// <exception cref="TransformationException">
    67→        /// Thrown when the transformation fails irrecoverably.
