    95→    public sealed class TransformationStrategyRegistry
    96→    {
    97→        private readonly ConcurrentDictionary<string, ITransformationStrategy> _strategies = new();
    98→
    99→        public void Register(ITransformationStrategy strategy)
   100→        {
   101→            ArgumentNullException.ThrowIfNull(strategy);
   102→            if (!_strategies.TryAdd(strategy.Identifier, strategy))
   103→            {
   104→                throw new InvalidOperationException(
   105→                    $"A strategy with id '{strategy.Identifier}' is already registered.");
