   115→    /// <summary>
   116→    /// High-level component that wires together the registry, the bounded
   117→    /// concurrency blocks, and the observer notifications.
   118→    /// </summary>
   119→    public sealed class TransformationPipeline : IAsyncDisposable
   120→    {
   121→        private readonly TransformationStrategyRegistry _registry;
   122→        private readonly ILogger<TransformationPipeline> _logger;
   123→        private readonly ActionBlock<DataRecord> _ingressBlock;
   124→        private readonly BroadcastBlock<DataRecord> _egressBlock;
   125→        private readonly CancellationTokenSource _cts = new();
   126→
   127→        /// <summary>
   128→        /// Creates a pipeline with the provided registry and logger.
   129→        /// </summary>
   130→        /// <param name="degreeOfParallelism">
   131→        /// Maximum number of concurrent strategy invocations.
   132→        /// </param>
   133→        /// <exception cref="ArgumentOutOfRangeException"/>
   134→        public TransformationPipeline(
   135→            TransformationStrategyRegistry registry,
   136→            ILogger<TransformationPipeline> logger,
   137→            int degreeOfParallelism = 8)
   138→        {
   139→            _registry = registry ?? throw new ArgumentNullException(nameof(registry));
   140→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   141→
   142→            if (degreeOfParallelism is <= 0 or > 256)
   143→            {
   144→                throw new ArgumentOutOfRangeException(
   145→                    nameof(degreeOfParallelism),
   146→                    "Must be between 1 and 256 inclusive.");
   147→            }
   148→
   149→            var execBlock = new TransformBlock<DataRecord, DataRecord>(
   150→                record => ApplyFirstMatchingStrategyAsync(record, _cts.Token),
   151→                new ExecutionDataflowBlockOptions
   152→                {
   153→                    MaxDegreeOfParallelism = degreeOfParallelism,
   154→                    BoundedCapacity = degreeOfParallelism * 4,
   155→                    CancellationToken = _cts.Token
   156→                });
   157→
   158→            _egressBlock = new BroadcastBlock<DataRecord>(r => r);
   159→            _ingressBlock = new ActionBlock<DataRecord>(record =>
   160→                    execBlock.Post(record),
   161→                new ExecutionDataflowBlockOptions
   162→                {
   163→                    MaxDegreeOfParallelism = 1,
   164→                    BoundedCapacity = degreeOfParallelism * 8,
   165→                    CancellationToken = _cts.Token
   166→                });
   167→
   168→            // Wire network: ingress -> exec -> egress
   169→            execBlock.LinkTo(_egressBlock, new DataflowLinkOptions { PropagateCompletion = true });
   170→
   171→            // Propagate completion & fault semantics
   172→            _ingressBlock.Completion.ContinueWith(t =>
   173→            {
   174→                if (t.IsFaulted)
   175→                    ((IDataflowBlock)_egressBlock).Fault(t.Exception!);
   176→                else
   177→                    _egressBlock.Complete();
   178→            });
   179→        }
   180→
   181→        /// <summary>
   182→        /// Posts a record into the pipeline asynchronously.
   183→        /// </summary>
   184→        public ValueTask<bool> SubmitAsync(
   185→            DataRecord record,
   186→            CancellationToken cancellationToken = default)
   187→        {
   188→            if (_cts.IsCancellationRequested) return ValueTask.FromResult(false);
   189→            return _ingressBlock.SendAsync(record, cancellationToken);
   190→        }
   191→
   192→        /// <summary>
   193→        /// Subscribes an asynchronous observer that is invoked for each
   194→        /// successful transformation result.
   195→        /// </summary>
   196→        public IDisposable Subscribe(Func<DataRecord, Task> onNextAsync)
   197→        {
   198→            ArgumentNullException.ThrowIfNull(onNextAsync);
   199→
   200→            // TransformBlock guarantees single invocations; we wrap via ActionBlock
   201→            var observerBlock = new ActionBlock<DataRecord>(onNextAsync, new ExecutionDataflowBlockOptions
   202→            {
   203→                MaxDegreeOfParallelism = 4,
   204→                BoundedCapacity = 128,
   205→                CancellationToken = _cts.Token
   206→            });
   207→
   208→            var link = _egressBlock.LinkTo(observerBlock,
   209→                new DataflowLinkOptions { PropagateCompletion = true });
   210→
   211→            return new DelegateDisposable(() =>
   212→            {
   213→                link.Dispose();
   214→                observerBlock.Complete();
   215→            });
   216→        }
   217→
   218→        /// <summary>
   219→        /// Gracefully completes & waits for pipeline flush.
   220→        /// </summary>
   221→        public async ValueTask DisposeAsync()
   222→        {
   223→            _ingressBlock.Complete();
   224→            _cts.CancelAfter(TimeSpan.FromSeconds(30));
   225→
   226→            try
   227→            {
   228→                await _egressBlock.Completion.ConfigureAwait(false);
   229→            }
   230→            finally
   231→            {
   232→                _cts.Dispose();
   233→            }
   234→        }
   235→
   236→        /// <summary>
   237→        /// Picks first strategy whose <see cref="ITransformationStrategy.CanHandle"/>
   238→        /// returns true, then executes it.  Records that do not match any
   239→        /// strategy are forwarded unchanged.
   240→        /// </summary>
   241→        private async Task<DataRecord> ApplyFirstMatchingStrategyAsync(
   242→            DataRecord record,
   243→            CancellationToken ct)
   244→        {
   245→            try
   246→            {
   247→                var strategy = _registry.All.FirstOrDefault(s => s.CanHandle(record));
   248→                if (strategy is null)
   249→                {
   250→                    _logger.LogDebug("No strategy accepted record from {Source}.  Skipping.",
   251→                        record.Source);
   252→                    return record;
   253→                }
   254→
   255→                _logger.LogTrace("Applying strategy {Strategy} to record from {Source}.",
   256→                    strategy.Identifier, record.Source);
   257→
   258→                var transformed = await strategy.TransformAsync(record, ct)
   259→                    .ConfigureAwait(false);
   260→
   261→                return transformed;
   262→            }
   263→            catch (TransformationException ex)
   264→            {
