   266→                _logger.LogWarning(ex, "Strategy failure for record from {Source}", record.Source);
   267→                throw;
   268→            }
   269→            catch (Exception ex)
   270→            {
   271→                _logger.LogError(ex, "Unhandled transformation exception.");
   272→                throw new TransformationException("Unhandled exception.", ex);
   273→            }
   274→        }
