   292→    #region Example Strategy — Focus Time Ratio ──────────────────────────────
   293→
   294→    /// <summary>
   295→    /// Calculates <c>Focus-Time Ratio = (Total_Focus_Time / Total_Work_Time)</c>
   296→    /// using calendar events classified via heuristics or ML models.  The
   297→    /// strategy operates on events that belong to a single employee and a
   298→    /// single day (UTC).  To avoid expensive IO, windowed aggregations are
   299→    /// cached for 10 minutes.
   300→    /// </summary>
   301→    public sealed class FocusTimeRatioStrategy : ITransformationStrategy
   302→    {
   303→        private const string SourceSystem = "calendar";
   304→        private const string MetricName = "focus_time_ratio";
   305→        private static readonly TimeSpan CacheTtl = TimeSpan.FromMinutes(10);
   306→
   307→        private readonly IMemoryCache _cache;
   308→        private readonly ILogger<FocusTimeRatioStrategy> _logger;
   309→
   310→        public FocusTimeRatioStrategy(IMemoryCache cache, ILogger<FocusTimeRatioStrategy> logger)
   311→        {
   312→            _cache = cache ?? throw new ArgumentNullException(nameof(cache));
   313→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   314→        }
   315→
   316→        public string Identifier => nameof(FocusTimeRatioStrategy);
   317→
   318→        public bool CanHandle(in DataRecord record) =>
   319→            record.Source.Equals(SourceSystem, StringComparison.OrdinalIgnoreCase) &&
   320→            record.Payload.TryGetValue("employee_id", out _) &&
   321→            record.Payload.TryGetValue("duration_minutes", out _) &&
   322→            record.Payload.TryGetValue("is_meeting", out _);
   323→
   324→        public async Task<DataRecord> TransformAsync(
   325→            DataRecord record,
   326→            CancellationToken cancellationToken = default)
   327→        {
   328→            cancellationToken.ThrowIfCancellationRequested();
   329→
   330→            var employeeId = record.Payload["employee_id"].ToString();
   331→            var duration = Convert.ToInt32(record.Payload["duration_minutes"]);
   332→            var isMeeting = Convert.ToBoolean(record.Payload["is_meeting"]);
   333→
   334→            var key = CacheKey(employeeId, record.Timestamp.Date);
   335→
   336→            // Each cache entry is the (focusMinutes, workMinutes) tuple.
   337→            var (focus, work) = _cache.GetOrCreate(key, entry =>
   338→            {
   339→                entry.AbsoluteExpirationRelativeToNow = CacheTtl;
   340→                return (focus: 0, work: 0);
   341→            });
   342→
   343→            // Update totals
   344→            work += duration;
   345→            if (!isMeeting) focus += duration;
   346→
   347→            _cache.Set(key, (focus, work), CacheTtl);
   348→
   349→            var ratio = work == 0 ? 0 : Math.Round(focus / (double)work, 4);
   350→
   351→            // Compose enriched record
   352→            var transformed = record with
   353→            {
   354→                Payload = new Dictionary<string, object>(record.Payload)
   355→                {
   356→                    ["metric"] = MetricName,
   357→                    ["focus_minutes"] = focus,
   358→                    ["work_minutes"] = work,
   359→                    [MetricName] = ratio
   360→                }
   361→            };
   362→
   363→            _logger.LogInformation(
   364→                "Computed {Metric}={Ratio} for Employee={Employee} on {Date}",
   365→                MetricName, ratio, employeeId, record.Timestamp.Date);
   366→
   367→            // Fake asynchronous call to demonstrate await pattern
   368→            await Task.Yield();
   369→
   370→            return transformed;
   371→        }
   372→
   373→        [MethodImpl(MethodImplOptions.AggressiveInlining)]
   374→        private static string CacheKey(string employeeId, DateTime dateUtc)
   375→            => $"{employeeId}:{dateUtc:yyyy-MM-dd}";
   376→    }
   377→
   378→    #endregion
   379→}
