    20→namespace PulseOps.Warehouse.Transformation
    21→{
    22→    /// <summary>
    23→    /// Raw event domain model as it comes off the lake.
    24→    /// </summary>
    25→    /// <param name="SourceSystem">The upstream system (Calendar, GitHub, Jira, etc.)</param>
    26→    /// <param name="Timestamp">UTC timestamp at source system.</param>
    27→    /// <param name="Payload">Opaque JSON payload.</param>
    28→    public sealed record RawEvent(string SourceSystem, DateTimeOffset Timestamp, JsonDocument Payload);
