    30→    /// <summary>
    31→    /// Normalized KPI result produced by a transformation strategy.
    32→    /// </summary>
    33→    /// <param name="KpiName">Unique KPI identifier.</param>
    34→    /// <param name="NumericValue">A numeric representation (for visualizations / alerting engines).</param>
    35→    /// <param name="CalculatedAt">Timestamp when KPI was calculated.</param>
    36→    /// <param name="Metadata">Optional, strategy-specific JSON metadata.</param>
    37→    public sealed record KpiResult(
    38→        string KpiName,
    39→        double NumericValue,
    40→        DateTimeOffset CalculatedAt,
    41→        JsonDocument? Metadata = null);
