    43→    /// <summary>
    44→    /// Strategy interface to calculate a KPI out of an arbitrary <see cref="IAsyncEnumerable{RawEvent}"/> stream.
    45→    /// </summary>
    46→    public interface ITransformationStrategy
    47→    {
    48→        /// <summary>
    49→        /// Human-friendly, unique name (used in configuration &amp; routing).
    50→        /// </summary>
    51→        string Name { get; }
    52→
    53→        /// <summary>
    54→        /// Executes the transformation.
    55→        /// </summary>
    56→        /// <exception cref="OperationCanceledException">Thrown if the caller cancels.</exception>
    57→        Task<KpiResult?> TransformAsync(IAsyncEnumerable<RawEvent> events, CancellationToken cancellationToken = default);
    58→    }
