    60→    /// <summary>
    61→    /// Calculates the "Focus-Time Ratio" KPI.
    62→    ///
    63→    /// Assumptions:
    64→    ///   ‑ Only events from the "Calendar" source are inspected.
    65→    ///   ‑ Each payload contains { "EventType": "Meeting" | "Focus", "DurationMinutes": int }.
    66→    /// </summary>
    67→    public sealed class FocusTimeRatioStrategy : ITransformationStrategy
    68→    {
    69→        public const string KpiKey = "focus_time_ratio";
    70→        public string Name => KpiKey;
    71→
    72→        private readonly ILogger _logger;
    73→
    74→        public FocusTimeRatioStrategy(ILogger<FocusTimeRatioStrategy> logger) => _logger = logger;
    75→
    76→        public async Task<KpiResult?> TransformAsync(IAsyncEnumerable<RawEvent> events, CancellationToken cancellationToken = default)
    77→        {
    78→            double focusMinutes = 0;
    79→            double meetingMinutes = 0;
    80→
    81→            await foreach (var e in events.WithCancellation(cancellationToken))
    82→            {
    83→                if (!e.SourceSystem.Equals("Calendar", StringComparison.OrdinalIgnoreCase))
    84→                    continue;
    85→
    86→                if (!e.Payload.RootElement.TryGetProperty("EventType", out var typeElement) ||
    87→                    !e.Payload.RootElement.TryGetProperty("DurationMinutes", out var durationElement))
    88→                {
    89→                    // Skip malformed.
    90→                    _logger.LogWarning("Calendar event missing required properties: {Payload}", e.Payload);
    91→                    continue;
    92→                }
    93→
    94→                var minutes = durationElement.GetDouble();
    95→                var eventType = typeElement.GetString();
    96→
    97→                switch (eventType)
    98→                {
    99→                    case "Focus":
   100→                        focusMinutes += minutes;
   101→                        break;
   102→
   103→                    case "Meeting":
   104→                        meetingMinutes += minutes;
   105→                        break;
   106→
   107→                    default:
   108→                        _logger.LogDebug("Ignoring Calendar event of type {EventType}", eventType);
   109→                        break;
   110→                }
   111→            }
   112→
   113→            var total = focusMinutes + meetingMinutes;
   114→            if (total <= 0)
   115→            {
   116→                _logger.LogInformation("No calendar entries detected. Focus-time ratio not computed.");
   117→                return null;
   118→            }
   119→
   120→            var ratio = focusMinutes / total;
   121→            _logger.LogInformation("Focus-Time Ratio computed: {Ratio:P2}", ratio);
   122→
   123→            var meta = JsonSerializer.SerializeToDocument(new
   124→            {
   125→                focusMinutes,
   126→                meetingMinutes,
   127→                ratio
   128→            });
   129→
   130→            return new KpiResult(KpiKey, ratio, DateTimeOffset.UtcNow, meta);
   131→        }
   132→    }
