   134→    /// <summary>
   135→    /// Calculates "Deployment Lead-Time" KPI.
   136→    ///
   137→    /// Assumptions:
   138→    ///   ‑ Events originate either from the "Git" or "CI" systems.
   139→    ///   ‑ Git payload: { "CommitSha": string, "CommittedAt": DateTime }
   140→    ///   ‑ CI payload : { "CommitSha": string, "DeployedAt": DateTime }
   141→    ///   ‑ Lead-time := DeployedAt ‑ CommittedAt, averaged across unique shas.
   142→    /// </summary>
   143→    public sealed class DeploymentLeadTimeStrategy : ITransformationStrategy
   144→    {
   145→        public const string KpiKey = "deployment_lead_time_minutes";
   146→        public string Name => KpiKey;
   147→
   148→        private readonly ILogger _logger;
   149→
   150→        public DeploymentLeadTimeStrategy(ILogger<DeploymentLeadTimeStrategy> logger)
   151→            => _logger = logger;
   152→
   153→        public async Task<KpiResult?> TransformAsync(IAsyncEnumerable<RawEvent> events, CancellationToken cancellationToken = default)
   154→        {
   155→            var commitTimestamps = new ConcurrentDictionary<string, DateTimeOffset>(); // sha -> committedAt
   156→            var deployTimestamps = new ConcurrentDictionary<string, DateTimeOffset>(); // sha -> deployedAt
   157→
   158→            await foreach (var e in events.WithCancellation(cancellationToken))
   159→            {
   160→                // Defensive: drain the stream quickly and avoid blocking logging I/O on hot path.
   161→                _ = Task.Run(() => ParseEvent(e), cancellationToken);
   162→            }
   163→
   164→            void ParseEvent(RawEvent ev)
   165→            {
   166→                try
   167→                {
   168→                    switch (ev.SourceSystem)
   169→                    {
   170→                        case "Git":
   171→                            commitTimestamps.TryAdd(
   172→                                ev.Payload.RootElement.GetProperty("CommitSha").GetString()!,
   173→                                ev.Payload.RootElement.GetProperty("CommittedAt").GetDateTime().ToUniversalTime());
   174→                            break;
   175→
   176→                        case "CI":
   177→                            deployTimestamps.TryAdd(
   178→                                ev.Payload.RootElement.GetProperty("CommitSha").GetString()!,
   179→                                ev.Payload.RootElement.GetProperty("DeployedAt").GetDateTime().ToUniversalTime());
   180→                            break;
   181→                    }
   182→                }
   183→                catch (Exception ex)
   184→                {
   185→                    _logger.LogWarning(ex, "Malformed {System} payload skipped: {Payload}", ev.SourceSystem, ev.Payload);
   186→                }
   187→            }
   188→
   189→            // Wait for all parsing tasks to drain (they're fire-and-forget but should finish by now).
   190→            await Task.Delay(100, cancellationToken);
   191→
   192→            var intersections = commitTimestamps.Keys.Intersect(deployTimestamps.Keys).ToList();
   193→            if (intersections.Count == 0)
   194→            {
   195→                _logger.LogInformation("No deployments matched to commits. Lead-time KPI not generated.");
   196→                return null;
   197→            }
   198→
   199→            var totalMinutes = intersections
   200→                .Select(sha => (deployTimestamps[sha] - commitTimestamps[sha]).TotalMinutes)
   201→                .Where(m => m >= 0 && m <= TimeSpan.FromDays(30).TotalMinutes) // ignore outliers
   202→                .ToList();
   203→
   204→            if (totalMinutes.Count == 0)
   205→            {
   206→                _logger.LogInformation("All candidate lead-times discarded as outliers.");
   207→                return null;
   208→            }
   209→
   210→            var avgMinutes = totalMinutes.Average();
   211→            _logger.LogInformation("Deployment Lead-Time calculated: {Minutes:F1} minutes", avgMinutes);
   212→
   213→            var meta = JsonSerializer.SerializeToDocument(new
   214→            {
   215→                observations = totalMinutes.Count,
   216→                averageMinutes = avgMinutes
   217→            });
   218→
   219→            return new KpiResult(KpiKey, avgMinutes, DateTimeOffset.UtcNow, meta);
   220→        }
   221→    }
