   314→    internal static class AsyncEnumerableExtensions
   315→    {
   316→        public static async Task<List<T>> ToListAsync<T>(this IAsyncEnumerable<T> source, CancellationToken ct = default)
   317→        {
   318→            var list = new List<T>();
   319→            await foreach (var item in source.WithCancellation(ct))
   320→            {
   321→                list.Add(item);
   322→            }
   323→
   324→            return list;
   325→        }
