    99→    /// <summary>
   100→    /// Calculates the focus-time ratio (maker vs meeting time) on a per-user/day basis.
   101→    /// </summary>
   102→    [TransformationStrategy("focus_time_ratio")]
   103→    public sealed class FocusTimeRatioStrategy : IKpiTransformationStrategy
   104→    {
   105→        private const string EventTypeMeeting      = "calendar_meeting";
   106→        private const string EventTypeCodeFocus    = "code_focus_window";
   107→        private static readonly TimeSpan OneMinute = TimeSpan.FromMinutes(1);
   108→
   109→        public string StrategyName => "focus_time_ratio";
   110→
   111→        public bool CanHandle(EventEnvelope envelope) =>
   112→            envelope.EventType is EventTypeMeeting or EventTypeCodeFocus;
   113→
   114→        public async IAsyncEnumerable<KpiRecord> TransformAsync(
   115→            IAsyncEnumerable<EventEnvelope> events,
   116→            [System.Runtime.CompilerServices.EnumeratorCancellation]
   117→            CancellationToken cancellationToken = default)
   118→        {
   119→            // group by user + date; accumulate durations
   120→            var buckets = new ConcurrentDictionary<(string user, DateOnly date),
   121→                                                   (double focusMinutes, double meetingMinutes)>();
   122→
   123→            await foreach (var envelope in events.WithCancellation(cancellationToken))
   124→            {
   125→                var user = ExtractUser(envelope) ?? "unknown";
   126→                var date = DateOnly.FromDateTime(envelope.Timestamp.UtcDateTime);
   127→
   128→                var durationMin = ExtractDurationMinutes(envelope);
   129→                if (durationMin < 0.01) continue; // guard against bogus durations
   130→
   131→                buckets.AddOrUpdate(
   132→                    (user, date),
   133→                    key => envelope.EventType == EventTypeCodeFocus
   134→                        ? (focusMinutes: durationMin, meetingMinutes: 0)
   135→                        : (focusMinutes: 0, meetingMinutes: durationMin),
   136→                    (key, existing) =>
   137→                    {
   138→                        if (envelope.EventType == EventTypeCodeFocus)
   139→                            return (existing.focusMinutes + durationMin, existing.meetingMinutes);
   140→                        return (existing.focusMinutes, existing.meetingMinutes + durationMin);
   141→                    });
   142→            }
   143→
   144→            foreach (var ((user, date), (focus, meeting)) in buckets)
   145→            {
   146→                var total = focus + meeting;
   147→                if (total < OneMinute.TotalMinutes) continue; // negligible — skip
   148→                yield return new KpiRecord
   149→                {
   150→                    KpiName   = "focus_time_ratio",
   151→                    Value     = focus / total,
   152→                    Dimensions = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase)
   153→                    {
   154→                        ["user"] = user,
   155→                        ["date"] = date.ToString("yyyy-MM-dd", CultureInfo.InvariantCulture)
   156→                    }
   157→                };
