   130→    /// <summary>
   131→    /// Reactive, high-performance aggregation engine.
   132→    /// Implements IObserver for ingestion and IObservable for metric fan-out.
   133→    /// </summary>
   134→    public sealed class TimeSeriesWindowAggregator : IObserver<ProductivityEvent>, IObservable<KpiMetric>, IAsyncDisposable
   135→    {
   136→        private readonly KpiAggregationDelegate _aggregationLogic;
   137→        private readonly TimeWindowOptions _options;
   138→
   139→        private readonly Subject<KpiMetric> _metricStream = new();
   140→        private readonly Channel<ProductivityEvent> _inputChannel;
   141→
   142→        // Concurrency primitives
   143→        private readonly CancellationTokenSource _cts = new();
   144→        private readonly Task _backgroundTask;
   145→
   146→        // Internal buffer storing events inside the current active window(s)
   147→        // We deliberately use a ConcurrentQueue to keep insertion O(1) and avoid
   148→        // global locks on the hot path.
   149→        private readonly ConcurrentQueue<ProductivityEvent> _buffer = new();
   150→
   151→        // Latest watermark processed (monotonic)
   152→        private DateTimeOffset _currentWindowCutoff;
   153→
   154→        public TimeSeriesWindowAggregator(
   155→            KpiAggregationDelegate aggregationLogic,
   156→            TimeWindowOptions options,
   157→            int boundedCapacity = 10_000) // backpressure
   158→        {
   159→            options.Validate();
   160→
   161→            _aggregationLogic = aggregationLogic ?? throw new ArgumentNullException(nameof(aggregationLogic));
   162→            _options = options;
   163→
   164→            _inputChannel = Channel.CreateBounded<ProductivityEvent>(new BoundedChannelOptions(boundedCapacity)
   165→            {
   166→                SingleReader = true,
   167→                SingleWriter = false,
   168→                FullMode = BoundedChannelFullMode.Wait
   169→            });
   170→
   171→            _currentWindowCutoff = AlignToWindowStart(DateTimeOffset.UtcNow);
   172→
   173→            _backgroundTask = Task.Factory.StartNew(
   174→                WorkLoopAsync,
   175→                _cts.Token,
   176→                TaskCreationOptions.LongRunning,
   177→                TaskScheduler.Default).Unwrap();
   178→        }
   179→
   180→        #region IObserver
   181→
   182→        public void OnNext(ProductivityEvent value)
   183→        {
   184→            if (!_inputChannel.Writer.TryWrite(value))
   185→            {
   186→                // backpressure fallback – should never happen due to boundedChannel Wait
   187→                throw new InvalidOperationException("Input channel rejected write unexpectedly.");
   188→            }
   189→        }
   190→
   191→        public void OnError(Exception error)
   192→        {
   193→            // Bubble up to downstream subscribers – they'll decide what to do.
   194→            _metricStream.OnError(error);
   195→        }
   196→
   197→        public void OnCompleted()
   198→        {
   199→            _inputChannel.Writer.Complete();
   200→        }
   201→
   202→        #endregion
   203→
   204→        #region IObservable
   205→
   206→        public IDisposable Subscribe(IObserver<KpiMetric> observer)
   207→        {
   208→            return _metricStream.AsObservable().Subscribe(observer);
   209→        }
   210→
   211→        #endregion
   212→
   213→        private async Task WorkLoopAsync()
   214→        {
   215→            try
   216→            {
   217→                var reader = _inputChannel.Reader;
   218→
   219→                while (await reader.WaitToReadAsync(_cts.Token).ConfigureAwait(false))
   220→                {
   221→                    while (reader.TryRead(out var evt))
   222→                    {
   223→                        _buffer.Enqueue(evt);
   224→                    }
   225→
   226→                    FlushExpiredWindows();
   227→                }
   228→            }
   229→            catch (OperationCanceledException)
   230→            {
   231→                // Normal shutdown – ignore.
   232→            }
   233→            catch (Exception ex)
   234→            {
   235→                // Surface unexpected exceptions so ops team is alerted (PagerDuty).
   236→                _metricStream.OnError(ex);
   237→            }
   238→            finally
   239→            {
   240→                _metricStream.OnCompleted();
   241→            }
   242→        }
   243→
   244→        /// <summary>
   245→        /// Remove records that no longer belong to any open window and emit
   246→        /// completed windows downstream.
   247→        /// </summary>
   248→        [MethodImpl(MethodImplOptions.AggressiveInlining)]
   249→        private void FlushExpiredWindows()
   250→        {
   251→            var now = DateTimeOffset.UtcNow;
   252→
   253→            // Move watermark forward in increments of SlideInterval until the current time is covered.
   254→            while (_currentWindowCutoff + _options.WindowSize <= now)
   255→            {
   256→                var windowStart = _currentWindowCutoff;
   257→                var windowEnd = windowStart + _options.WindowSize;
   258→
   259→                // Gather relevant events.
   260→                var windowEvents = DrainEvents(windowStart, windowEnd);
   261→
   262→                // Apply user-supplied aggregation delegate.
   263→                try
   264→                {
   265→                    foreach (var metric in _aggregationLogic(windowEvents, windowStart, windowEnd))
   266→                    {
   267→                        _metricStream.OnNext(metric);
   268→                    }
   269→                }
   270→                catch (Exception ex)
   271→                {
   272→                    // Fail-fast on faulty business logic so we don't silently produce wrong numbers.
   273→                    _metricStream.OnError(new AggregationException(
   274→                        $"Aggregation delegate threw for window {windowStart:o}-{windowEnd:o}", ex));
   275→                }
   276→
   277→                // Advance watermark
   278→                _currentWindowCutoff = windowStart + _options.SlideInterval;
   279→            }
   280→        }
