   282→        /// <summary>
   283→        /// Retrieve and remove events from the buffer that are part of the
   284→        /// requested window interval.
   285→        /// </summary>
   286→        private IReadOnlyCollection<ProductivityEvent> DrainEvents(DateTimeOffset windowStart, DateTimeOffset windowEnd)
   287→        {
   288→            var set = new List<ProductivityEvent>(capacity: 1024);
