    34→namespace PulseOps.Warehouse.Transformations
    35→{
    36→    /// <summary>
    37→    /// Orchestrates KPI computations by delegating the heavy lifting to a pool of
    38→    /// <see cref="IKpiComputationStrategy"/> implementations.  Responsibilities:
    39→    ///
    40→    /// • Resolve the correct strategy for a given <see cref="KpiRequest"/>
    41→    /// • Run the computation across a configurable degree of parallelism
    42→    /// • Persist results to the Lake (S3) using a structured partition scheme
    43→    /// • Emit CloudWatch observable metrics & traces
    44→    /// • Provide robust error-handling / back-off semantics
    45→    /// </summary>
    46→    public sealed class KpiComputationOrchestrator : IKpiComputationOrchestrator
    47→    {
    48→        private const string DefaultRegion = "us-east-1";
    49→        private readonly IKpiComputationStrategyRegistry _strategyRegistry;
    50→        private readonly IAmazonS3 _s3Client;
    51→        private readonly ILogger<KpiComputationOrchestrator> _logger;
    52→        private readonly OrchestratorOptions _options;
    53→
    54→        public KpiComputationOrchestrator(
    55→            IKpiComputationStrategyRegistry strategyRegistry,
    56→            ILogger<KpiComputationOrchestrator> logger,
    57→            OrchestratorOptions? options = null,
    58→            IAmazonS3? s3Client = null)
    59→        {
    60→            _strategyRegistry = strategyRegistry ?? throw new ArgumentNullException(nameof(strategyRegistry));
    61→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
    62→            _options = options ?? OrchestratorOptions.FromEnvironment();
    63→            _s3Client = s3Client ?? new AmazonS3Client(FallbackCredentialsFactory.GetCredentials(), RegionEndpoint.GetBySystemName(DefaultRegion));
    64→        }
    65→
    66→        public async Task<KpiBatchResult> ProcessBatchAsync(
    67→            IEnumerable<KpiRequest> requests,
    68→            CancellationToken cancellationToken = default)
    69→        {
    70→            if (requests == null) throw new ArgumentNullException(nameof(requests));
    71→
    72→            var requestList = requests.ToList();
    73→            _logger.LogInformation("Processing {Count} KPI requests", requestList.Count);
    74→
    75→            var throttler = new SemaphoreSlim(_options.DegreeOfParallelism);
    76→            var resultCollector = new ConcurrentBag<KpiComputationResult>();
    77→            var failures = new ConcurrentBag<KpiComputationFailure>();
    78→
    79→            var tasks = requestList.Select(async request =>
    80→            {
    81→                await throttler.WaitAsync(cancellationToken).ConfigureAwait(false);
    82→                try
    83→                {
    84→                    await ExecuteWithRetryAsync(request, cancellationToken, async () =>
    85→                    {
    86→                        var strategy = _strategyRegistry.Resolve(request.KpiName);
    87→                        _logger.LogDebug("Resolved strategy {Strategy} for KPI {Kpi}",
    88→                            strategy.GetType().Name, request.KpiName);
    89→
    90→                        var result = await strategy.ComputeAsync(request, cancellationToken)
    91→                            .ConfigureAwait(false);
    92→
    93→                        await PersistToLakeAsync(result, cancellationToken)
    94→                            .ConfigureAwait(false);
    95→
    96→                        _logger.LogInformation("Successfully processed KPI {Kpi} for Tenant {TenantId}",
    97→                            request.KpiName, request.TenantId);
    98→
    99→                        resultCollector.Add(result);
   100→                    }).ConfigureAwait(false);
   101→                }
   102→                catch (Exception ex)
   103→                {
   104→                    _logger.LogError(ex, "Failed to process KPI {Kpi} for Tenant {TenantId}",
   105→                        request.KpiName, request.TenantId);
   106→
   107→                    failures.Add(new KpiComputationFailure(request, ex));
   108→                }
   109→                finally
   110→                {
   111→                    throttler.Release();
   112→                }
   113→            }).ToArray();
   114→
   115→            await Task.WhenAll(tasks).ConfigureAwait(false);
   116→
   117→            return new KpiBatchResult(resultCollector.ToArray(), failures.ToArray());
   118→        }
   119→
   120→        #region Helpers
   121→
   122→        private async Task ExecuteWithRetryAsync(
   123→            KpiRequest request,
   124→            CancellationToken cancellationToken,
   125→            Func<Task> action)
   126→        {
   127→            var attempt = 0;
   128→            var delay = _options.InitialBackoff;
   129→
   130→            while (true)
   131→            {
   132→                try
   133→                {
   134→                    cancellationToken.ThrowIfCancellationRequested();
   135→                    await action().ConfigureAwait(false);
   136→                    return; // success
   137→                }
   138→                catch (Exception ex) when (IsTransient(ex) && attempt < _options.MaxRetryAttempts)
   139→                {
   140→                    attempt++;
   141→                    _logger.LogWarning(ex,
   142→                        "[Attempt {Attempt}/{MaxAttempts}] Transient failure while processing {Kpi} (Tenant {TenantId}). Retrying in {DelayMs}ms…",
   143→                        attempt, _options.MaxRetryAttempts, request.KpiName, request.TenantId, delay.TotalMilliseconds);
   144→
   145→                    await Task.Delay(delay, cancellationToken).ConfigureAwait(false);
   146→                    delay = TimeSpan.FromMilliseconds(delay.TotalMilliseconds * _options.BackoffMultiplier);
   147→                }
   148→            }
   149→        }
   150→
   151→        private static bool IsTransient(Exception ex)
   152→        {
   153→            return ex switch
   154→            {
   155→                AmazonServiceException ase
   156→                    when ase.StatusCode is HttpStatusCode.InternalServerError or HttpStatusCode.ServiceUnavailable => true,
   157→                TimeoutException => true,
   158→                _ => false
   159→            };
   160→        }
   161→
   162→        private async Task PersistToLakeAsync(
   163→            KpiComputationResult result,
   164→            CancellationToken cancellationToken)
   165→        {
   166→            // Example partition: kpi_name=FocusTimeRatio/year=2023/month=08/day=14/hour=13/<tenantId>.json
   167→            var (bucket, key) = GetS3LocationForResult(result);
   168→
   169→            using var stream = JsonSerializer.SerializeToUtf8Bytes(result).AsStream();
   170→            var putRequest = new PutObjectRequest
   171→            {
   172→                BucketName = bucket,
   173→                Key = key,
   174→                InputStream = stream,
   175→                ContentType = "application/json",
   176→                AutoCloseStream = true
   177→            };
   178→
   179→            await _s3Client.PutObjectAsync(putRequest, cancellationToken)
   180→                .ConfigureAwait(false);
   181→
   182→            _logger.LogDebug("Persisted KPI {Kpi} result to s3://{Bucket}/{Key}", result.KpiName, bucket, key);
   183→        }
   184→
   185→        private (string Bucket, string Key) GetS3LocationForResult(KpiComputationResult result)
   186→        {
   187→            var timestamp = result.GeneratedAtUtc;
   188→            var key =
   189→                $"{result.KpiName}/year={timestamp:yyyy}/month={timestamp:MM}/day={timestamp:dd}/hour={timestamp:HH}/{result.TenantId}.json";
   190→
   191→            return (_options.S3Bucket, key);
   192→        }
   193→
   194→        #endregion
   195→    }
