     5→//  Component:   Transformation Strategy Resolver (Strategy_Pattern)
     6→//  ----------------------------------------------------------------------------
     7→//  Description:
     8→//      • Dynamically discovers, materializes, and caches transformation
     9→//        strategies that implement ITransformationStrategy.
    10→//      • Enables hot-swappable business logic without redeploying Lambda mesh.
    11→//      • Provides a concrete example strategy (FocusTimeStrategy).
    12→// -----------------------------------------------------------------------------
    13→
    14→using System;
    15→using System.Collections.Concurrent;
    16→using System.Collections.Generic;
    17→using System.Linq;
    18→using System.Reflection;
    19→using Microsoft.Extensions.Logging;
    20→
    21→namespace PulseOps.Warehouse.Transformations
    22→{
    23→    /// <summary>
    24→    /// Attribute used to decorate <see cref="ITransformationStrategy"/> implementations
    25→    /// with discoverable metadata (e.g., logical name & version).
    26→    /// </summary>
    27→    [AttributeUsage(AttributeTargets.Class, AllowMultiple = false)]
    28→    public sealed class StrategyMetadataAttribute : Attribute
    29→    {
    30→        public string Name   { get; }
    31→        public string Version { get; }
    32→
    33→        public StrategyMetadataAttribute(string name, string version = "1.0")
    34→        {
    35→            if (string.IsNullOrWhiteSpace(name))
    36→                throw new ArgumentException("Strategy name cannot be null or whitespace.", nameof(name));
    37→
    38→            Name    = name.Trim();
    39→            Version = version?.Trim() ?? "1.0";
    40→        }
    41→    }
    42→
    43→    /// <summary>
    44→    /// Base contract for any data-transformation strategy plugged into the
    45→    /// Pipeline_Pattern. Implementations are expected to be stateless & thread-safe.
    46→    /// </summary>
    47→    public interface ITransformationStrategy
    48→    {
    49→        /// <summary>
    50→        /// Fallback key when <see cref="StrategyMetadataAttribute"/> is omitted.
    51→        /// </summary>
    52→        string Key { get; }
    53→
    54→        /// <summary>
    55→        /// Execute transformation against the incoming <paramref name="input"/>.
    56→        /// </summary>
    57→        /// <param name="input">Arbitrary payload: JSON, domain model, parquet row, etc.</param>
    58→        /// <returns>Transformed object or <c>null</c> if no output is produced.</returns>
    59→        object? Execute(object input);
    60→    }
    61→
    62→    /// <summary>
    63→    /// Public contract for resolving <see cref="ITransformationStrategy"/> instances.
    64→    /// </summary>
    65→    public interface ITransformationStrategyResolver
    66→    {
    67→        /// <summary>
    68→        /// Resolve a strategy by logical key.
    69→        /// </summary>
    70→        ITransformationStrategy GetStrategy(string key);
    71→
    72→        /// <summary>
    73→        /// Enumerate all registered strategy keys.
    74→        /// </summary>
    75→        IEnumerable<string> ListStrategies();
    76→    }
    77→
    78→    /// <summary>
    79→    /// Exception thrown when a requested transformation strategy cannot be found.
    80→    /// </summary>
    81→    public sealed class StrategyNotFoundException : Exception
    82→    {
    83→        public StrategyNotFoundException(string? message) : base(message) { }
    84→        public StrategyNotFoundException(string? message, Exception? innerException)
    85→            : base(message, innerException) { }
    86→    }
    87→
    88→    /// <summary>
    89→    /// Implementation of <see cref="ITransformationStrategyResolver"/> that discovers
    90→    /// strategies via reflection and lazily instantiates them through <see cref="Activator"/>.
    91→    /// </summary>
    92→    public sealed class TransformationStrategyResolver : ITransformationStrategyResolver, IDisposable
    93→    {
    94→        private readonly ILogger<TransformationStrategyResolver> _logger;
    95→        private readonly IServiceProvider                         _serviceProvider;
    96→
    97→        // Thread-safe cache (key -> Lazy(strategy))
    98→        private readonly ConcurrentDictionary<string, Lazy<ITransformationStrategy>> _cache =
    99→            new(StringComparer.OrdinalIgnoreCase);
   100→
   101→        private readonly HashSet<Assembly> _processedAssemblies = new();
   102→        private readonly object            _syncRoot           = new();
   103→
   104→        private bool _disposed;
   105→
   106→        public TransformationStrategyResolver(
   107→            ILogger<TransformationStrategyResolver> logger,
   108→            IServiceProvider                         serviceProvider)
   109→        {
   110→            _logger          = logger          ?? throw new ArgumentNullException(nameof(logger));
   111→            _serviceProvider = serviceProvider ?? throw new ArgumentNullException(nameof(serviceProvider));
   112→
   113→            // Warm-up with already-loaded assemblies.
   114→            DiscoverStrategies(AppDomain.CurrentDomain.GetAssemblies());
   115→        }
   116→
   117→        /// <inheritdoc/>
   118→        public ITransformationStrategy GetStrategy(string key)
   119→        {
   120→            if (string.IsNullOrWhiteSpace(key))
   121→                throw new ArgumentException("Strategy key must be provided.", nameof(key));
   122→
   123→            EnsureNotDisposed();
   124→
   125→            if (_cache.TryGetValue(key, out var lazy))
   126→                return lazy.Value;
   127→
   128→            // Plug-ins might be loaded at runtime—perform a defensive rescan.
   129→            lock (_syncRoot)
   130→            {
   131→                if (!_cache.ContainsKey(key))
   132→                    DiscoverStrategies(AppDomain.CurrentDomain
   133→                                       .GetAssemblies()
   134→                                       .Where(a => !_processedAssemblies.Contains(a)));
   135→            }
   136→
   137→            if (_cache.TryGetValue(key, out lazy))
   138→                return lazy.Value;
   139→
   140→            throw new StrategyNotFoundException(
   141→                $"Transformation strategy with key '{key}' was not found.");
   142→        }
   143→
   144→        /// <inheritdoc/>
   145→        public IEnumerable<string> ListStrategies()
   146→        {
   147→            EnsureNotDisposed();
   148→            return _cache.Keys.ToArray();
   149→        }
   150→
   151→        // ---------------------------------------------------------------------
   152→        //  Discovery Logic
   153→        // ---------------------------------------------------------------------
   154→        private void DiscoverStrategies(IEnumerable<Assembly> assemblies)
   155→        {
   156→            foreach (var assembly in assemblies.Where(a => !_processedAssemblies.Contains(a)))
   157→            {
   158→                try
   159→                {
   160→                    foreach (var candidate in assembly.GetTypes()
   161→                                                      .Where(t => !t.IsAbstract &&
   162→                                                                  typeof(ITransformationStrategy)
   163→                                                                      .IsAssignableFrom(t)))
   164→                    {
   165→                        var metadata = candidate.GetCustomAttribute<StrategyMetadataAttribute>();
   166→                        var key      = metadata?.Name ?? candidate.Name;
   167→
   168→                        _cache.GetOrAdd(
   169→                            key,
   170→                            _ => new Lazy<ITransformationStrategy>(() =>
   171→                            {
   172→                                try
   173→                                {
   174→                                    var instance = (ITransformationStrategy)
   175→                                                   Activator.CreateInstance(candidate)!;
   176→                                    _logger.LogInformation(
   177→                                        "Loaded transformation strategy {Strategy} (v{Version})",
   178→                                        key,
   179→                                        metadata?.Version ?? "1.0");
   180→                                    return instance;
   181→                                }
   182→                                catch (Exception ex)
   183→                                {
   184→                                    _logger.LogError(
   185→                                        ex,
   186→                                        "Failed to instantiate transformation strategy '{Strategy}'.",
   187→                                        key);
   188→                                    throw;
   189→                                }
   190→                            }));
   191→                    }
   192→
   193→                    _processedAssemblies.Add(assembly);
   194→                }
   195→                catch (ReflectionTypeLoadException ex)
   196→                {
   197→                    _logger.LogWarning(
   198→                        ex,
   199→                        "ReflectionTypeLoadException while scanning assembly {Assembly}.",
   200→                        assembly.FullName);
   201→                }
   202→            }
   203→        }
   204→
   205→        // ---------------------------------------------------------------------
   206→        //  IDisposable
   207→        // ---------------------------------------------------------------------
   208→        public void Dispose()
   209→        {
   210→            if (_disposed) return;
   211→
   212→            foreach (var (_, lazy) in _cache)
   213→            {
   214→                if (lazy.IsValueCreated && lazy.Value is IDisposable disposable)
   215→                    disposable.Dispose();
   216→            }
   217→
   218→            _cache.Clear();
   219→            _disposed = true;
   220→            GC.SuppressFinalize(this);
   221→        }
   222→
   223→        private void EnsureNotDisposed()
   224→        {
   225→            if (_disposed)
   226→                throw new ObjectDisposedException(nameof(TransformationStrategyResolver));
   227→        }
   228→    }
   229→}
