   234→namespace PulseOps.Warehouse.Transformations.Strategies
   235→{
   236→    using System.Collections.Generic;
   237→    using System.Linq;
   238→
   239→    /// <summary>
   240→    /// Calculates the ratio between focus-time and total calendar time over a time
   241→    /// slice. Intended to ingest enriched calendar events produced by earlier
   242→    /// ETL stages.
   243→    ///
   244→    /// Example output:
   245→    ///     { "FocusRatio": 0.42 }
   246→    /// </summary>
   247→    [PulseOps.Warehouse.Transformations.StrategyMetadata("FocusTime", "2.1")]
   248→    public sealed class FocusTimeStrategy : PulseOps.Warehouse.Transformations.ITransformationStrategy
   249→    {
   250→        public string Key => "FocusTime";
   251→
   252→        public object Execute(object input)
   253→        {
   254→            if (input is not IReadOnlyCollection<CalendarEvent> events)
   255→            {
   256→                throw new ArgumentException(
   257→                    $"Expected {typeof(IReadOnlyCollection<CalendarEvent>).FullName} but " +
   258→                    $"received {input?.GetType().FullName}.",
   259→                    nameof(input));
   260→            }
   261→
   262→            var focusMinutes  = events.Where(e => e.IsFocusTime).Sum(e => e.DurationMinutes);
   263→            var totalMinutes  = events.Sum(e  => e.DurationMinutes);
   264→
   265→            var ratio = totalMinutes == 0
   266→                ? 0.0
   267→                : focusMinutes / (double) totalMinutes;
   268→
   269→            return new { FocusRatio = ratio };
   270→        }
   271→    }
   272→
   273→    /// <summary>
   274→    /// Simplified calendar event domain model used by <see cref="FocusTimeStrategy"/>.
   275→    /// </summary>
   276→    public record CalendarEvent(DateTimeOffset Start,
   277→                                DateTimeOffset End,
   278→                                bool           IsFocusTime)
   279→    {
   280→        public int DurationMinutes => (int) (End - Start).TotalMinutes;
   281→    }
   282→}
