   314→    internal sealed class DeploymentLeadTimeStrategy : ITransformationStrategy
   315→    {
   316→        private const string MetricName = "deployment_lead_time_seconds";
   317→
   318→        public string EventType => "CI_PIPELINE_COMPLETED";
   319→
   320→        public Task<TransformedEvent> TransformAsync(RawEvent raw, CancellationToken token)
   321→        {
   322→            var startedAt  = raw.Payload.GetProperty("pipelineStartedAt").GetDateTimeOffset();
   323→            var finishedAt = raw.Payload.GetProperty("pipelineFinishedAt").GetDateTimeOffset();
   324→            var duration   = (finishedAt - startedAt).TotalSeconds;
   325→
   326→            var transformed = new TransformedEvent
   327→            {
   328→                TenantId   = raw.TenantId,
   329→                EventType  = "DEPLOYMENT_LEAD_TIME",
   330→                OccurredAt = raw.OccurredAt,
   331→                Metrics    = new Dictionary<string, object?>
   332→                {
   333→                    [MetricName] = duration
   334→                }
   335→            };
   336→
   337→            return Task.FromResult(transformed);
   338→        }
   339→    }
