    78→    public async Task HandlerAsync(KinesisEvent kinesisEvent, ILambdaContext context)
    79→    {
    80→        if (kinesisEvent?.Records == null || kinesisEvent.Records.Count == 0)
    81→        {
    82→            _logger.LogWarning("Invocation contained zero Kinesis records.");
    83→            return;
    84→        }
