    47→public sealed class KpiTransformerFunction
    48→{
    49→    private readonly KpiStrategyResolver _strategyResolver;
    50→    private readonly IAmazonKinesisFirehose _firehoseClient;
    51→    private readonly string _outputStreamName;
    52→    private readonly string _errorStreamName;
    53→    private const int FirehosePutRecordBatchLimit = 500;
    54→
    55→    public KpiTransformerFunction()
    56→        : this(
    57→            firehoseClient: new AmazonKinesisFirehoseClient(
    58→                new AmazonKinesisFirehoseConfig { RegionEndpoint = RegionEndpoint.GetBySystemName(Environment.GetEnvironmentVariable("AWS_REGION") ?? "us-east-1") }
    59→            ),
    60→            new KpiStrategyResolver()
    61→        )
    62→    {
    63→        /* no-op — delegates to overload */
    64→    }
    65→
    66→    // For unit-tests + DI
    67→    internal KpiTransformerFunction(IAmazonKinesisFirehose firehoseClient, KpiStrategyResolver strategyResolver)
    68→    {
    69→        _firehoseClient = firehoseClient ?? throw new ArgumentNullException(nameof(firehoseClient));
    70→        _strategyResolver = strategyResolver ?? throw new ArgumentNullException(nameof(strategyResolver));
    71→
    72→        _outputStreamName = Environment.GetEnvironmentVariable("FIREHOSE_STREAM_NAME") ??
    73→                            throw new InvalidOperationException("FIREHOSE_STREAM_NAME env-var must be defined.");
    74→
    75→        _errorStreamName = Environment.GetEnvironmentVariable("FIREHOSE_ERROR_STREAM_NAME") ??
    76→                           $"{_outputStreamName}-dlq"; // fallback
    77→    }
    78→
    79→    /// <summary>
    80→    ///     Lambda handler invoked by AWS runtime.
    81→    /// </summary>
    82→    /// <param name="kinesisEvent">Batch of Kinesis records.</param>
    83→    /// <param name="context">Execution context.</param>
    84→    /// <returns>Async task.</returns>
    85→    public async Task HandlerAsync(KinesisEvent kinesisEvent, ILambdaContext context)
    86→    {
    87→        var logger = context.Logger;
    88→
    89→        var successes = new ConcurrentBag<Record>();
    90→        var failures  = new ConcurrentBag<Record>();
    91→
    92→        var processTasks = new List<Task>();
    93→
    94→        foreach (var record in kinesisEvent.Records)
    95→        {
    96→            processTasks.Add(ProcessRecordAsync(record, successes, failures, logger, context.CancellationToken));
    97→        }
    98→
    99→        await Task.WhenAll(processTasks);
   100→
   101→        // Flush successes first
   102→        if (!successes.IsEmpty)
   103→        {
   104→            await FlushBatchAsync(successes, _outputStreamName, logger, context.CancellationToken);
   105→            logger.LogInformation($"Successfully processed {successes.Count} KPI records.");
   106→        }
   107→
   108→        // Flush failures to dedicated DLQ Firehose stream
   109→        if (!failures.IsEmpty)
   110→        {
   111→            await FlushBatchAsync(failures, _errorStreamName, logger, context.CancellationToken);
   112→            logger.LogError($"{failures.Count} records failed KPI transformation and were sent to DLQ '{_errorStreamName}'.");
   113→        }
   114→    }
