   116→    #region ────────────────────────────────── Private helpers ──────────────────────────────────
   117→
   118→    private async Task ProcessRecordAsync(
   119→        KinesisEvent.KinesisEventRecord kinesisRecord,
   120→        ConcurrentBag<Record> successBag,
   121→        ConcurrentBag<Record> failureBag,
   122→        ILambdaLogger logger,
   123→        CancellationToken cancellationToken)
   124→    {
   125→        try
   126→        {
   127→            var rawJson = Encoding.UTF8.GetString(kinesisRecord.Kinesis.Data.Span);
   128→
   129→            using var jsonDoc = JsonDocument.Parse(rawJson);
   130→            var root = jsonDoc.RootElement;
   131→
   132→            var kpiType = root.GetProperty("kpiType").GetString();
   133→            if (string.IsNullOrWhiteSpace(kpiType))
   134→            {
   135→                throw new JsonException("kpiType property missing or empty.");
   136→            }
   137→
   138→            var strategy = _strategyResolver.Resolve(kpiType);
   139→            if (strategy is null)
   140→            {
   141→                throw new InvalidOperationException($"No strategy registered that can handle KPI type '{kpiType}'.");
   142→            }
   143→
   144→            var result = await strategy.CalculateAsync(root.GetProperty("data"), cancellationToken);
   145→
   146→            var resultJson = JsonSerializer.Serialize(result, KpiJsonSerializerContext.Default.KpiResult);
   147→
   148→            successBag.Add(new Record
   149→            {
   150→                Data = new MemoryStream(Encoding.UTF8.GetBytes(resultJson))
   151→            });
   152→        }
   153→        catch (Exception ex)
   154→        {
   155→            logger.LogError(ex, $"Failed to transform event {kinesisRecord.EventId}.");
   156→
   157→            var errorPayload = new
   158→            {
   159→                error     = ex.Message,
   160→                stack     = ex.StackTrace,
   161→                timestamp = DateTimeOffset.UtcNow,
   162→                original  = Convert.ToBase64String(kinesisRecord.Kinesis.Data.ToArray())
   163→            };
   164→
   165→            var errorJson = JsonSerializer.Serialize(errorPayload);
   166→            failureBag.Add(new Record
   167→            {
   168→                Data = new MemoryStream(Encoding.UTF8.GetBytes(errorJson))
   169→            });
   170→        }
