   173→    private async Task FlushBatchAsync(IEnumerable<Record> records, string deliveryStreamName, ILambdaLogger logger, CancellationToken token)
   174→    {
   175→        var batch = new List<Record>(FirehosePutRecordBatchLimit);
   176→
   177→        foreach (var rec in records)
   178→        {
   179→            batch.Add(rec);
   180→
   181→            if (batch.Count == FirehosePutRecordBatchLimit)
   182→            {
   183→                await PutAsync(batch, deliveryStreamName, logger, token);
   184→                batch.Clear();
   185→            }
   186→        }
   187→
   188→        if (batch.Count > 0)
   189→        {
   190→            await PutAsync(batch, deliveryStreamName, logger, token);
   191→        }
   192→    }
   193→
   194→    private async Task PutAsync(IReadOnlyCollection<Record> batch, string streamName, ILambdaLogger logger, CancellationToken token)
   195→    {
   196→        var response = await _firehoseClient.PutRecordBatchAsync(
   197→            new PutRecordBatchRequest(streamName, new List<Record>(batch)),
   198→            token
   199→        );
   200→
   201→        if (response.FailedPutCount > 0)
   202→        {
   203→            logger.LogError($"Firehose PutRecordBatchAsync reported {response.FailedPutCount} failures for stream {streamName}.");
   204→        }
   205→    }
