   213→internal interface IKpiStrategy
   214→{
   215→    bool CanHandle(string kpiType);
   216→
   217→    /// <summary>
   218→    ///     Calculates KPI result for the supplied JSON payload. Implementations
   219→    ///     must remain pure — no side-effects or network traffic.
