   227→internal sealed class KpiStrategyResolver
   228→{
   229→    private readonly IReadOnlyList<IKpiStrategy> _strategies;
   230→
   231→    public KpiStrategyResolver()
   232→    {
   233→        _strategies = new IKpiStrategy[]
   234→        {
   235→            new FocusTimeRatioStrategy(),
   236→            new MeetingCostIndexStrategy()
   237→        };
   238→    }
   239→
   240→    public IKpiStrategy? Resolve(string kpiType)
   241→    {
   242→        foreach (var strategy in _strategies)
   243→        {
   244→            if (strategy.CanHandle(kpiType))
   245→            {
   246→                return strategy;
