   254→/// <summary>
   255→///     Result record produced by KPI strategies.
   256→/// </summary>
   257→public sealed record KpiResult(
   258→    string KpiType,
   259→    double Value,
   260→    DateTimeOffset CalculatedAtUtc,
   261→    JsonElement Metadata
