   264→#region ─────────────────────────────── Strategy Implementations ───────────────────────────────
   265→
   266→/// <summary>
   267→///     Calculates “Focus-Time Ratio” per event as
   268→///     1 − (meetingDuration / workingWindowDuration).  For example, a 1-hour
   269→///     meeting inside an 8-hour day yields 0.875.
   270→/// </summary>
   271→internal sealed class FocusTimeRatioStrategy : IKpiStrategy
   272→{
   273→    private const string KpiId = "FocusTimeRatio";
   274→
   275→    public bool CanHandle(string kpiType) => string.Equals(kpiType, KpiId, StringComparison.OrdinalIgnoreCase);
   276→
   277→    public Task<KpiResult> CalculateAsync(JsonElement data, CancellationToken token)
   278→    {
   279→        var meetingStart = data.GetProperty("startTime").GetDateTimeOffset();
   280→        var meetingEnd   = data.GetProperty("endTime").GetDateTimeOffset();
   281→        var workingWindowMinutes = data.TryGetProperty("workingWindowMinutes", out var windowElement)
   282→            ? windowElement.GetInt32()
   283→            : 480; // default 8-hour work-day
   284→
   285→        var meetingMinutes = (meetingEnd - meetingStart).TotalMinutes;
   286→        var ratio          = 1 - (meetingMinutes / workingWindowMinutes);
   287→
   288→        ratio = Math.Clamp(ratio, 0, 1);
   289→
   290→        return Task.FromResult(new KpiResult(
   291→            KpiType: KpiId,
   292→            Value: ratio,
   293→            CalculatedAtUtc: DateTimeOffset.UtcNow,
   294→            Metadata: data
   295→        ));
   296→    }
   297→}
