   299→/// <summary>
   300→///     Calculates “Meeting Cost Index” as (# attendees × durationHours × hourlyRate).
   301→/// </summary>
   302→internal sealed class MeetingCostIndexStrategy : IKpiStrategy
   303→{
   304→    private const string KpiId = "MeetingCostIndex";
   305→
   306→    public bool CanHandle(string kpiType) => string.Equals(kpiType, KpiId, StringComparison.OrdinalIgnoreCase);
   307→
   308→    public Task<KpiResult> CalculateAsync(JsonElement data, CancellationToken token)
   309→    {
   310→        var attendees     = data.GetProperty("attendeesCount").GetInt32();
   311→        var hourlyRate    = data.TryGetProperty("hourlyRate",   out var rateEl) ? rateEl.GetDouble() : 75.0;
