   115→        public async Task TransformAsync(
   116→            IAsyncEnumerable<RawProductivityEvent> events,
   117→            IAsyncEventWriter<FocusTimeRatioKpi>   outputWriter,
   118→            CancellationToken                      cancellationToken = default)
