   147→        #region Buffer & Flushing
   148→
   149→        private async Task FlushBufferAsync(
   150→            IAsyncEventWriter<FocusTimeRatioKpi>? writer = default,
   151→            CancellationToken                     ct     = default)
   152→        {
   153→            if (_buffer.IsEmpty) return;
   154→
   155→            var channel = Channel.CreateUnbounded<FocusTimeRatioKpi>(
   156→                new UnboundedChannelOptions
   157→                {
   158→                    SingleReader      = false,
   159→                    SingleWriter      = false,
   160→                    AllowSynchronousContinuations = false
   161→                });
