   163→            // Producer: convert aggregates into KPI DTOs.
   164→            _ = Task.Run(async () =>
   165→            {
   166→                try
   167→                {
   168→                    foreach (var (key, aggregate) in _buffer.ToArray())
   169→                    {
   170→                        // Remove from buffer atomically if still exists.
   171→                        if (_buffer.TryRemove(key, out var agg))
   172→                        {
   173→                            var kpi = agg.ToKpi();
   174→
   175→                            await channel.Writer
   176→                                         .WriteAsync(kpi, ct)
   177→                                         .ConfigureAwait(false);
   178→                        }
   179→                    }
   180→                }
   181→                catch (Exception ex)
   182→                {
   183→                    _logger?.LogError(ex, "Failed while enqueuing KPIs for flush.");
   184→                }
   185→                finally
   186→                {
   187→                    channel.Writer.Complete();
   188→                }
   189→            }, ct);
