   191→            // Consumer: write out via provided writer (if streaming), else just log.
   192→            await foreach (var kpi in channel.Reader.ReadAllAsync(ct)
   193→                                                    .ConfigureAwait(false))
   194→            {
   195→                try
   196→                {
   197→                    if (writer is not null)
   198→                    {
   199→                        await writer.WriteAsync(kpi, ct)
   200→                                    .ConfigureAwait(false);
   201→                    }
