   203→                    {
   204→                        _logger?.LogInformation(
   205→                            "KPI flushed (dry-run): {kpi}",
   206→                            JsonSerializer.Serialize(kpi));
   207→                    }
   208→                }
   209→                catch (Exception ex)
   210→                {
   211→                    _logger?.LogWarning(
   212→                        ex,
   213→                        "Failed to persist KPI for EmployeeId={EmployeeId} Date={Date}",
   214→                        kpi.EmployeeId,
   215→                        kpi.Date.ToString("yyyy-MM-dd",
   216→                                          CultureInfo.InvariantCulture));
   217→                }
   218→            }
   219→        }
   220→
   221→        #endregion
   222→
   223→        #region Aggregate – private helper
   224→
   225→        private sealed class Aggregate
   226→        {
   227→            public string   EmployeeId     { get; }
   228→            public DateTime Date           { get; }
   229→            public double   FocusMinutes   { get; private set; }
   230→            public double   MeetingMinutes { get; private set; }
