   232→            private Aggregate(string employeeId, DateTime date)
   233→            {
   234→                EmployeeId = employeeId;
   235→                Date       = date;
   236→            }
   237→
   238→            public static Aggregate New(string employeeId, DateTime date, RawProductivityEvent evt)
   239→            {
   240→                var agg = new Aggregate(employeeId, date);
   241→                return agg.Add(evt);
   242→            }
   243→
   244→            /// <summary>
   245→            /// Thread-safe accumulation of a new event into the aggregate.
   246→            /// </summary>
   247→            public Aggregate Add(RawProductivityEvent evt)
   248→            {
   249→                var minutes = evt.Duration.TotalMinutes;
   250→                switch (evt.Kind)
   251→                {
   252→                    case EventKind.FocusSession:
   253→                        InterlockedAdd(ref FocusMinutes, minutes);
   254→                        break;
   255→
   256→                    case EventKind.Meeting:
