   270→                    EmployeeId,
   271→                    Date,
   272→                    Math.Round(FocusMinutes,   2),
   273→                    Math.Round(MeetingMinutes, 2),
   274→                    Math.Round(ratio,          4));
   275→            }
   276→
   277→            private static void InterlockedAdd(ref double location, double value)
   278→            {
   279→                double newCurrentValue, currentValue;
   280→                do
   281→                {
   282→                    currentValue   = location;
   283→                    newCurrentValue = currentValue + value;
   284→                }
   285→                while (Math.Abs(
   286→                           Interlocked.CompareExchange(
   287→                               ref location,
   288→                               newCurrentValue,
   289→                               currentValue) - currentValue) > double.Epsilon);
   290→            }
   291→        }
   292→
   293→        #endregion
   294→
   295→        public void Dispose()
   296→        {
   297→            _flushTimer.Dispose();
