   116→    public sealed class FocusTimeRatioStrategy : ITransformationStrategy<CalendarEvent, IReadOnlyCollection<FocusTimeRatioKpi>>
   117→    {
   118→        public const string StrategyId = "focus-time-ratio@v1";
   119→        private const string DefaultFocusLabel = "Focus";
   120→        private static readonly string[] EquivalentFocusLabels = { "Deep-Work", "Heads-Down" };
   121→
