   135→            {
   136→                var kpis = events
   137→                    .Where(evt => evt.Start.Date == evt.End.Date) // Skip multi-day events for simplicity
   138→                    .GroupBy(evt => new { evt.UserPrincipalName, Day = DateOnly.FromDateTime(evt.Start.Date) })
   139→                    .Select(group =>
   140→                    {
