   108→   108→    public sealed class FocusTimeRatioStrategy : ITransformationStrategy
   109→   109→    {
   110→   110→        private readonly ILogger<FocusTimeRatioStrategy> _logger;
   111→   111→        private static readonly TimeSpan MinimumSessionLength = TimeSpan.FromMinutes(5);
   112→   112→
   113→   113→        public FocusTimeRatioStrategy(ILogger<FocusTimeRatioStrategy> logger) => _logger = logger;
   114→   114→
   115→   115→        public KpiType TargetKpi => KpiType.FocusTimeRatio;
   116→   116→
   117→   117→        public ValueTask<IReadOnlyCollection<KpiRecord>> TransformAsync(
   118→   118→            IEnumerable<RawEvent> events,
   119→   119→            CancellationToken cancellationToken = default)
   120→   120→        {
   121→   121→            _logger.LogDebug("Starting FocusTimeRatio transformation on {EventCount} events.", events.Count());
   122→   122→
   123→   123→            // Group events by hour-long windows (Sliding granularity can be implemented via configuration).
   124→   124→            var grouped = events
   125→   125→                .GroupBy(e => new { e.TenantId, WindowStart = TruncateToHour(e.Timestamp.UtcDateTime) })
   126→   126→                .ToImmutableArray();
   127→   127→
   128→   128→            var result = new List<KpiRecord>(grouped.Length);
   129→   129→
   130→   130→            foreach (var bucket in grouped)
   131→   131→            {
   132→   132→                cancellationToken.ThrowIfCancellationRequested();
   133→   133→
   134→   134→                double focusMinutes = 0;
   135→   135→                double totalMinutes = 60; // 1-hour window by definition.
   136→   136→
   137→   137→                // Very simplified heuristic: events from IDE / code editors contribute to focus-time,
   138→   138→                // whereas calendar events eat from that pie.
   139→   139→                foreach (var ev in bucket)
   140→   140→                {
   141→   141→                    if (ev.Source.Equals("IDE", StringComparison.OrdinalIgnoreCase))
   142→   142→                    {
   143→   143→                        focusMinutes += MinimumSessionLength.TotalMinutes;
   144→   144→                    }
   145→   145→                    else if (ev.Source.Equals("Calendar", StringComparison.OrdinalIgnoreCase))
   146→   146→                    {
   147→   147→                        focusMinutes -= MinimumSessionLength.TotalMinutes;
   148→   148→                    }
   149→   149→                }
   150→   150→
   151→   151→                var ratio = Math.Clamp(focusMinutes / totalMinutes, 0, 1);
