   154→   154→                    TenantId: bucket.Key.TenantId,
   155→   155→                    WindowStart: bucket.Key.WindowStart,
   156→   156→                    WindowEnd: bucket.Key.WindowStart.AddHours(1),
   157→   157→                    Type: KpiType.FocusTimeRatio,
   158→   158→                    Value: Convert.ToDecimal(ratio),
   159→   159→                    Dimensions: null));
