   161→   161→                _logger.LogTrace(
   162→   162→                    "Computed FocusTimeRatio = {Ratio:P2} for tenant {Tenant} at window {Window}.",
   163→   163→                    ratio,
   164→   164→                    bucket.Key.TenantId,
   165→   165→                    bucket.Key.WindowStart);
   166→   166→            }
