y>\n    40→    public enum KpiType\n    41→    {\n    42→        FocusTimeRatio,\n    43→        DeploymentLeadTime,\n    44→        MeetingCostIndex,\n    45→        //  Future KPIs can be added here—no changes required to the orchestrator.\n    46→    }\n    47→\n    48→    /// <summary>\n    49→    /// Canonical representation of the raw, “silver-tier” event.\n    50→    /// </summary>\n    51→    /// <param name=\"TenantId\">Customer / tenant identifier.</param>\n    52→    /// <param name=\"Timestamp\">UTC time when the event originally occurred.</param>\n    53→    /// <param name=\"Source\">Logical upstream system (e.g. GitHub, Zoom, Jira).</param>\n    54→    /// <param name=\"Payload\">Opaque, source-specific payload.</param>\n    55→    public sealed record RawEvent(\n    56→        string TenantId,\n    57→        DateTimeOffset Timestamp,\n    58→        string Source,\n    59→        IReadOnlyDictionary<string, object> Payload);\n    60→\n    61→    /// <summary>\n    62→    /// Output record produced by a transformation strategy.\n    63→    /// </summary>\n    64→    /// <param name=\"TenantId\">Customer / tenant identifier.</param>\n    65→    /// <param name=\"WindowStart\">Inclusive window start (UTC).</param>\n    66→    /// <param name=\"WindowEnd\">Exclusive window end (UTC).</param>\n    67→    /// <param name=\"Type\">Computed KPI type.</param>\n    68→    /// <param name=\"Value\">Computed KPI numeric value.</param>\n    69→    /// <param name=\"Dimensions\">Arbitrary dimension key/value pairs that enable downstream slicing.</param>\n    70→    public sealed record KpiRecord(\n    71→        string TenantId,\n    72→        DateTimeOffset WindowStart,\n    73→        DateTimeOffset WindowEnd,\n    74→        KpiType Type,\n    75→        decimal Value,\n    76→        IReadOnlyDictionary<string, string>? Dimensions);\n    77→\n    78→    /// <summary>\n    79→    /// Contract for KPI-specific transformation strategies.\n    80→    /// </summary>\n    81→    public interface ITransformationStrategy\n    82→    {\n    83→        /// <summary>\n    84→        /// Target KPI implemented by the strategy.\n    85→        /// </summary>\n    86→        KpiType TargetKpi { get; }\n    87→\n    88→        /// <summary>\n    89→        /// Performs the actual transformation.\n    90→        /// </summary>\n    91→        /// <param name=\"events\">Raw events from the same tenant and time range.</param>\n    92→        /// <param name=\"cancellationToken\">Cancellation token propagated from the orchestrator.</param>\n    93→        /// <returns>\n    94→        /// One or more <see cref=\"KpiRecord\"/> instances.  Multiple records allow\n    95→        /// drill-in by dimension (e.g. per repository).\n    96→        /// </returns>\n    97→        ValueTask<IReadOnlyCollection<KpiRecord>> TransformAsync(\n    98→            IEnumerable<RawEvent> events,\n    99→            CancellationToken cancellationToken = default);\n   100→    }\n   101→\n   102→    // -----------------------  Concrete Strategy Implementations -----------------------\n   103→\n   104→    /// <summary>\n   105→    /// Computes ratio of individual focus time (deep work) to the total time\n   106→    /// span covered by calendar + workstation activity events.\n   107→    /// </summary>\n   108→    public sealed class FocusTimeRatioStrategy : ITransformationStrategy\n   109→    {\n   110→        private readonly ILogger<FocusTimeRatioStrategy> _logger;\n   111→        private static readonly TimeSpan MinimumSessionLength = TimeSpan.FromMinutes(5);\n   112→\n   113→        public FocusTimeRatioStrategy(ILogger<FocusTimeRatioStrategy> logger) => _logger = logger;\n   114→\n   115→        public KpiType TargetKpi => KpiType.FocusTimeRatio;\n   116→\n   117→        public ValueTask<IReadOnlyCollection<KpiRecord>> TransformAsync(\n   118→            IEnumerable<RawEvent> events,\n   119→            CancellationToken cancellationToken = default)\n   120→        {\n   121→            _logger.LogDebug(\"Starting FocusTimeRatio transformation on {EventCount} events.\", events.Count());\n   122→\n   123→            // Group events by hour-long windows (Sliding granularity can be implemented via configuration).\n   124→            var grouped = events\n   125→                .GroupBy(e => new { e.TenantId, WindowStart = TruncateToHour(e.Timestamp.UtcDateTime) })\n   126→                .ToImmutableArray();\n   127→\n   128→            var result = new List<KpiRecord>(grouped.Length);\n   129→\n   130→            foreach (var bucket in grouped)\n   131→            {\n   132→                cancellationToken.ThrowIfCancellationRequested();\n   133→\n   134→                double focusMinutes = 0;\n   135→                double totalMinutes = 60; // 1-hour window by definition.\n   136→\n   137→                // Very simplified heuristic: events from IDE / code editors contribute to focus-time,\n   138→                // whereas calendar events eat from that pie.\n   139→                foreach (var ev in bucket)\n   140→                {\n   141→                    if (ev.Source.Equals(\"IDE\", StringComparison.OrdinalIgnoreCase))\n   142→                    {\n   143→                        focusMinutes += MinimumSessionLength.TotalMinutes;\n   144→                    }\n   145→                    else if (ev.Source.Equals(\"Calendar\", StringComparison.OrdinalIgnoreCase))\n   146→                    {\n   147→                        focusMinutes -= MinimumSessionLength.TotalMinutes;\n   148→                    }\n   149→                }\n   150→\n   151→                var ratio = Math.Clamp(focusMinutes / totalMinutes, 0, 1);\n   152→\n   153→                result.Add(new KpiRecord(\n   154→                    TenantId: bucket.Key.TenantId,\n   155→                    WindowStart: bucket.Key.WindowStart,\n   156→                    WindowEnd: bucket.Key.WindowStart.AddHours(1),\n   157→                    Type: KpiType.FocusTimeRatio,\n   158→                    Value: Convert.ToDecimal(ratio),\n   159→                    Dimensions: null));\n   160→\n   161→                _logger.LogTrace(\n   162→                    \"Computed FocusTimeRatio = {Ratio:P2} for tenant {Tenant} at window {Window}.\",\n   163→                    ratio,\n   164→                    bucket.Key.TenantId,\n   165→                    bucket.Key.WindowStart);\n   166→            }\n   167→\n   168→            return ValueTask.FromResult<IReadOnlyCollection<KpiRecord>>(result);\n   169→        }\n   170→\n   171→        private static DateTimeOffset TruncateToHour(DateTime dateTime) =>\n   172→            new(dateTime.Year, dateTime.Month, dateTime.Day, dateTime.Hour, 0, 0, TimeSpan.Zero);\n   173→    }\n   174→\n   175→    /// <summary>\n   176→    /// Computes the lead-time between a commit reaching the default branch and\n   177→    /// that commit being deployed to production.\n   178→    /// </summary>\n   179→    public sealed class DeploymentLeadTimeStrategy : ITransformationStrategy\n   180→    {\n   181→        private readonly ILogger<DeploymentLeadTimeStrategy> _logger;\n   182→\n   183→        public DeploymentLeadTimeStrategy(ILogger<DeploymentLeadTimeStrategy> logger) => _logger = logger;\n   184→\n   185→        public KpiType TargetKpi => KpiType.DeploymentLeadTime;\n   186→\n   187→        public async ValueTask<IReadOnlyCollection<KpiRecord>> TransformAsync(\n   188→            IEnumerable<RawEvent> events,\n   189→            CancellationToken cancellationToken = default)\n   190→        {\n   191→            _logger.LogDebug(\"Starting DeploymentLeadTime transformation.\");\n   192→\n   193→            // Because lead-time spans multiple events, we must correlate commit-sha.\n   194→            var commits = events.Where(e => e.Source == \"GitHub\" && e.Payload.TryGetValue(\"commit_sha\", out _));\n   195→            var deployments = events.Where(e => e.Source == \"CD\" && e.Payloa