   115→    /// <summary>
   116→    /// Writes failed events to an Amazon Kinesis stream for replay or inspection.
   117→    /// </summary>
   118→    public sealed class KinesisDeadLetterSink : IDeadLetterSink
   119→    {
   120→        private const int MaxPayloadBytes = 1_000_000; // 1 MB Kinesis hard-limit (rounded down)
   121→
   122→        private readonly IAmazonKinesis               _kinesis;
   123→        private readonly string                       _streamName;
   124→        private readonly ILogger<KinesisDeadLetterSink> _logger;
   125→
   126→        public KinesisDeadLetterSink(
   127→            IAmazonKinesis               kinesis,
   128→            string                       streamName,
   129→            ILogger<KinesisDeadLetterSink> logger)
   130→        {
   131→            _kinesis    = kinesis                      ?? throw new ArgumentNullException(nameof(kinesis));
   132→            _streamName = string.IsNullOrWhiteSpace(streamName)
   133→                            ? throw new ArgumentException("Stream name must be supplied.", nameof(streamName))
   134→                            : streamName;
   135→            _logger     = logger                       ?? throw new ArgumentNullException(nameof(logger));
   136→        }
   137→
   138→        public async Task PublishAsync(EventEnvelope envelope, Exception ex, CancellationToken ct = default)
   139→        {
   140→            var dlqPayload = new
   141→            {
   142→                envelope.Id,
   143→                envelope.EventType,
   144→                envelope.Timestamp,
   145→                envelope.Payload,
   146→                Error       = ex.ToString(),
   147→                PublishedAt = DateTimeOffset.UtcNow
   148→            };
   149→
   150→            var bytes = JsonSerializer.SerializeToUtf8Bytes(dlqPayload);
   151→
   152→            if (bytes.Length > MaxPayloadBytes)
   153→            {
   154→                _logger.LogWarning(
   155→                    "DLQ payload exceeds the 1 MB limit and will be discarded. EventId={EventId}",
   156→                    envelope.Id);
   157→                return;
   158→            }
   159→
   160→            var request = new PutRecordRequest
   161→            {
   162→                StreamName   = _streamName,
   163→                PartitionKey = envelope.Id,
   164→                Data         = new MemoryStream(bytes)
   165→            };
   166→
   167→            await _kinesis.PutRecordAsync(request, ct).ConfigureAwait(false);
   168→        }
   169→    }
