   175→    /// <summary>
   176→    /// Computes the ratio of uninterrupted focus-time to total work-time
   177→    /// from raw calendar events.
   178→    /// </summary>
   179→    public sealed class FocusTimeStrategy : ITransformationStrategy
   180→    {
   181→        private readonly ILogger<FocusTimeStrategy> _logger;
   182→
   183→        public FocusTimeStrategy(ILogger<FocusTimeStrategy> logger) =>
   184→            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
   185→
   186→        public bool CanHandle(EventEnvelope envelope) =>
   187→            string.Equals(envelope.EventType, "calendar.event", StringComparison.OrdinalIgnoreCase);
   188→
   189→        public Task<KpiRecord?> TransformAsync(EventEnvelope envelope, CancellationToken ct)
   190→        {
   191→            try
   192→            {
   193→                var payload = envelope.Payload;
   194→
   195→                if (!payload.TryGetProperty("meetingLengthMinutes", out var meetingProp) ||
   196→                    !payload.TryGetProperty("workdayLengthMinutes", out var workdayProp))
   197→                {
   198→                    throw new InvalidEventSchemaException(envelope.Id, "Missing meeting/workday duration.");
   199→                }
   200→
   201→                var meetingMinutes = meetingProp.GetInt32();
   202→                var workdayMinutes = workdayProp.GetInt32();
   203→
   204→                var ratio = (double)(workdayMinutes - meetingMinutes) / workdayMinutes;
   205→
   206→                return Task.FromResult<KpiRecord?>(new KpiRecord(
   207→                    Name       : "focus_time_ratio",
   208→                    Value      : Math.Round(ratio, 4),
   209→                    Unit       : "ratio",
   210→                    Timestamp  : envelope.Timestamp,
   211→                    Dimensions : new Dictionary<string, string>
   212→                    {
   213→                        ["event_id"] = envelope.Id
   214→                    }));
   215→            }
   216→            catch (Exception ex) when (ex is not InvalidEventSchemaException)
   217→            {
   218→                _logger.LogError(ex, "FocusTime transformation failed for EventId={EventId}", envelope.Id);
   219→                throw;
   220→            }
   221→        }
   222→    }
